css:
* { margin: 0; padding: 0; box-sizing: border-box; }
body { font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif; background: #fafafa; color: #1a1a1a; }
header { background: white; border-bottom: 1px solid #e5e7eb; position: sticky; top: 0; z-index: 100; }
.header-top { display: flex; align-items: center; justify-content: space-between; padding: 12px 48px; border-bottom: 1px solid #e5e7eb; }
.date { font-size: 12px; color: #9ca3af; }
.logo { font-size: 28px; font-weight: 900; letter-spacing: 4px; color: #dc2626; }
.sub-btn { padding: 8px 18px; border-radius: 6px; border: none; background: #dc2626; color: white; font-weight: 700; font-size: 13px; cursor: pointer; }
nav { display: flex; gap: 28px; padding: 0 48px; } nav a { display: block; padding: 14px 0; font-size: 14px; font-weight: 600; color: #6b7280; text-decoration: none; border-bottom: 2px solid transparent; cursor: pointer; transition: all 0.2s; } nav a:hover, nav a.active { color: #dc2626; border-bottom-color: #dc2626; }
.breaking { background: #dc2626; color: white; padding: 10px 48px; display: flex; align-items: center; gap: 16px; font-size: 13px; }
.breaking-label { background: white; color: #dc2626; padding: 2px 10px; border-radius: 4px; font-weight: 900; font-size: 11px; white-space: nowrap; }
.breaking-text { font-weight: 600; }
main { max-width: 1200px; margin: 0 auto; padding: 28px 48px; }
.featured-grid { display: grid; grid-template-columns: 1.6fr 1fr; gap: 24px; margin-bottom: 32px; }
.feature-main { border-radius: 16px; overflow: hidden; background: white; border: 1px solid #e5e7eb; cursor: pointer; transition: box-shadow 0.2s; } .feature-main:hover { box-shadow: 0 8px 24px rgba(0,0,0,0.08); }
.fm-img { height: 240px; background: linear-gradient(135deg, #1e3a5f, #dc2626); display: flex; align-items: center; justify-content: center; font-size: 80px; }
.fm-content { padding: 20px; }
.feature-main h1 { font-size: 22px; font-weight: 800; line-height: 1.3; margin: 10px 0 10px; }
.feature-main p { color: #6b7280; font-size: 14px; line-height: 1.6; margin-bottom: 12px; }
.feature-side { display: flex; flex-direction: column; gap: 16px; }
.side-article { display: flex; gap: 14px; align-items: center; background: white; border: 1px solid #e5e7eb; border-radius: 12px; padding: 14px; cursor: pointer; transition: all 0.2s; } .side-article:hover { border-color: #dc2626; }
.sa-img { font-size: 40px; width: 60px; height: 60px; background: #f1f5f9; border-radius: 10px; display: flex; align-items: center; justify-content: center; flex-shrink: 0; }
.sa-content { flex: 1; } .sa-content h3 { font-size: 14px; font-weight: 700; line-height: 1.35; margin: 6px 0 6px; }
.category-tag { display: inline-block; padding: 3px 8px; border-radius: 4px; font-size: 10px; font-weight: 800; letter-spacing: 1px; }
.tech { background: #eff6ff; color: #2563eb; } .economy { background: #f0fdf4; color: #16a34a; } .culture { background: #fdf4ff; color: #9333ea; } .sport { background: #fff7ed; color: #ea580c; } .life { background: #fdf2f8; color: #db2777; }
.article-meta { display: flex; gap: 8px; font-size: 12px; color: #9ca3af; flex-wrap: wrap; } .article-meta.small { font-size: 11px; margin-top: 4px; }
.content-row { display: grid; grid-template-columns: 1fr 300px; gap: 28px; }
.section-title { font-size: 18px; font-weight: 800; margin-bottom: 16px; padding-bottom: 10px; border-bottom: 2px solid #dc2626; }
.list-article { display: flex; gap: 16px; padding: 20px; background: white; border: 1px solid #e5e7eb; border-radius: 12px; margin-bottom: 12px; cursor: pointer; transition: all 0.2s; } .list-article:hover { border-color: #dc2626; }
.la-num { font-size: 36px; font-weight: 900; color: #e5e7eb; flex-shrink: 0; } .la-content h3 { font-size: 16px; font-weight: 700; margin: 6px 0 8px; line-height: 1.3; } .la-content p { color: #6b7280; font-size: 13px; margin-bottom: 8px; }
.trending-widget, .newsletter-widget { background: white; border: 1px solid #e5e7eb; border-radius: 12px; padding: 20px; margin-bottom: 16px; }
.trending-widget h3, .newsletter-widget h3 { font-size: 16px; font-weight: 800; margin-bottom: 16px; }
.trending-list { display: flex; flex-direction: column; gap: 12px; }
.tr-item { display: flex; gap: 12px; align-items: flex-start; cursor: pointer; } .tr-num { width: 24px; height: 24px; border-radius: 50%; background: #dc2626; color: white; font-size: 11px; font-weight: 800; display: flex; align-items: center; justify-content: center; flex-shrink: 0; } .tr-title { font-size: 13px; font-weight: 600; line-height: 1.4; }
.newsletter-widget p { color: #6b7280; font-size: 13px; margin-bottom: 12px; }
.newsletter-widget input { width: 100%; height: 40px; border-radius: 8px; border: 1px solid #e5e7eb; padding: 0 12px; font-size: 13px; outline: none; margin-bottom: 8px; }
.newsletter-widget button { width: 100%; height: 40px; border-radius: 8px; border: none; background: #dc2626; color: white; font-weight: 700; cursor: pointer; font-size: 14px; }
